   SET LOGIN_DATE = SYSDATE
	 , LATEST_LOGIN_IP #{latestLoginIp}
	 , LOGIN_FAIL_COUNT = 0
	 , LATEST_LOGIN_FAIL_DATE = NULL
 WHERE EMAIL = #{email}
